import{_ as e,p as i,q as l,a1 as o}from"./framework-96b046e1.js";const a="/images/ams1117.png",c="/images/ams1117-LDO电路.png",s={},t=o('<h2 id="线性稳压芯片-ldo" tabindex="-1"><a class="header-anchor" href="#线性稳压芯片-ldo" aria-hidden="true">#</a> 线性稳压芯片 LDO</h2><p>我用的线性稳压芯片有：</p><ul><li>AMS1117 <ul><li>封装：SOT-223\\SOT-89</li><li>输入：最大 15V，压差 1.3V@(1A)</li><li>输出：3.3V\\5V、1.8V、其他</li><li>输出电流：1A</li><li>AMS1117 也有可调输出版本的芯片 ADJ</li></ul></li><li>ME6211C33M5G <ul><li>输出：3.3V/500mA、3V/500mA、其他</li><li>输入：最大 6V</li><li>封装：SOT-23-5</li><li>使能引脚：带使能引脚</li></ul></li></ul><h2 id="ams1117-3-3" tabindex="-1"><a class="header-anchor" href="#ams1117-3-3" aria-hidden="true">#</a> AMS1117-3.3</h2><p><code>AMS1117</code> 是一款常用的线性稳压芯片，下面是经典的线性稳压电路，其实线性稳压芯片的电路都是类似的，输入和输入各加上两个滤波电容，一个0.1uF用于滤除高频干扰，一个大容量的用于稳定低频扰动。</p><p>滤波电容的参数主要有两个：<strong>耐压值</strong>和<strong>容量</strong>，耐压值必须大于工作电压，输入端和输入端都要有一个 <code>0.1uF</code> 的电容，用于滤除电路中的高频干扰，另外两个大容量的容值根据功率而定，一般 <code>100uF</code> 左右即可，如果是其他大功率的 <code>LDO</code> 可以选择更多容量的电容。</p><p><img src="'+a+'" alt=""></p><p>另外电压电路一般都会设计一个 <code>led</code> 指示灯，就是一个 <code>LED</code> 串上一个电阻。</p><p><img src="'+c+'" alt=""></p>',9),d=[t];function r(n,p){return i(),l("div",null,d)}const m=e(s,[["render",r],["__file","LDO.html.vue"]]);export{m as default};
